#!/bin/bash
set -euo pipefail

# usage:
#     bash rpp-rename.sh
#
# you'll need GNU sed installed: `brew install gnu-sed`

# Check if any arguments are provided
if [[ $# -gt 0 ]]; then
  # Add all provided arguments to the paths array
  for i in "$@"; do
    paths+=("$i")
  done
else
  paths=(

    "core"
    
    # NOT front_end/third_party/*
  )
fi

files=()
for path in "${paths[@]}"; do
  files+=($(find "$path" -type f \( ! -name "BUILD.gn" -a ! -name "OWNERS" \) -a ! -path "*fixtures/traces*"  ))
done


replace_in_files() {
  local file="$1"
  # The order below is important

  # Pass A
  gsed -i -E  $"s/\btraceParsedData\b/parsedTrace/g;\
                s/\btraceParseData\b/parsedTrace/g;\
                s/TraceParsedData/ParsedTrace/g;\
                s/TraceParseData/ParsedTrace/g;\
                s/\bKnownEventName\b/Name/g;\
                s/TraceEventData/Event/g;\
                s/traceEventData/event/g;\
                s/TraceEventHandler/Handler/g;\
                s/traceEngineData/parsedTrace/g;\
                s/TraceEngineData/ParsedTrace/g;\
                s/createParsedTraceFromEvents/createTraceEngineDataFromEvents/g;\
                s/TraceEngine\b/Trace/g;\
                s/Types\.TraceEvents\b/Types\.Events/g;\
                s/as TraceEvents /as Events /g;\
                s/Synthetic(\w+)Event(s?)\b/Synthetic\1\2/g;\
                s/synthetic(\w+)Event(s?)\b/synthetic\1\2/g;\
                s/traceParseData/parsedTrace/g;\
                s/traceParsedData/parsedTrace/g;\
                s/parsedTraceData/parsedTrace/g;\
                s/fromTraceData\b/fromParsedTrace/g;\
                s/\btraceData\b/parsedTrace/g;\
                s/traceData([0-9])/parsedTrace\1/g;\
                s/traceEngineParsedData\b/traceEngineParsedTrace/g;\
                s/traceDataIndex/parsedTraceIndex/g;\
                s/availableTraceDataIndexes/availableparsedTraceIndexes/g;\
                s/activeTraceDataIndex/activeparsedTraceIndex/g;\
                s/parsedTrace: parsedTrace,/parsedTrace,/g;\
                s/registerSyntheticBased\b/registerSyntheticEvent/g;\
                s/lastoneisnonsense/NONSENSEEEEEEEEEEEEE/g" "$file";

  gsed -i -z -E $"s/(import (type )?\* as Trace from '..\/..\/..\/models\/trace\/trace\.js';\n){2}/import * as Trace from '..\/..\/..\/models\/trace\/trace.js';\n/g" "$file"

  # Pass B
  gsed -i -E  $"s/isTraceEventAsyncPhase\((.*?)\)/isPhaseAsync(\1.ph)/g;\
                s/isPhaseAsync\(event\)\.ph/isPhaseAsync(event.ph)/g;\
                s/isAsyncPhase/isPhaseAsync/g;\
                s/([.|&<s ])TraceEvent([A-Z])/\1\2/g;\
                s/lastoneisnonsense/NONSENSEEEEEEEEEEEEE/g" "$file";


  # Pass C
  gsed -i -E  $"s/TraceInsightData\b/TraceInsightSets/g;\
                s/BoundedInsights/InsightSets/g;\
                s/BoundedInsight/InsightSet/g;\
                s/boundedInsight/insightSet/g;\
                s/traceInsightsData/traceInsightsSets/g;\
                s/\b#insights\b/#insightSets/g;\
                s/\TraceEngineInsightData/TraceInsightSets/g;\
                s/lastoneisnonsense/NONSENSEEEEEEEEEEEEE/g" "$file";


  # These are dumb, but oh well
  gsed -i -E  $"s/TODO: Trace is not retaining/TODO: Trace Engine is not retaining/g;\
                s/Trace collects worker thread ids/Trace Engine collects worker thread ids/g;\
                s/WorkersHandler in Trace needs/WorkersHandler in Trace Engine needs/g;\
                s/Trace consolidates all redirects/Trace Engine consolidates all redirects/g;\
                s/Trace will report progress/Trace Engine will report progress/g;\
                s/Trace events are in microseconds/Trace Engine events are in microseconds/g;\
                s/using the types from Trace,/using the types from Trace Engine,/g;\
                s/Trace. If it does/Trace Engine. If it does/g;\
                s/representation of parsedTrace line/representation of the TraceObject file line/g;\
              s/lastoneisnonsense/NONSENSEEEEEEEEEEEEE/g" "$file";
}


replace_in_tests() {
  local file="$1"

  gsed -i -E  $"s/\sTraceModel\b/ Trace/g;\
                s/import * as TraceModel from (.*?trace.js)/import * as Trace from \1/g;\
                s/TraceModel\.Extras/Trace.Extras/g;\
                s/TraceModel\.Handlers/Trace.Handlers/g;\
                s/TraceModel\.Helpers/Trace.Helpers/g;\
                s/TraceModel\.Insights/Trace.Insights/g;\
                s/TraceModel\.Lantern/Trace.Lantern/g;\
                s/TraceModel\.LanternComputationData/Trace.LanternComputationData/g;\
                s/TraceModel\.Processor/Trace.Processor/g;\
                s/TraceModel\.RootCauses/Trace.RootCauses/g;\
                s/TraceModel\.TraceModel/Trace.TraceModel/g;\
                s/TraceModel\.TracingManager/Trace.TracingManager/g;\
                s/TraceModel\.Types/Trace.Types/g;\
                s/lastoneisnonsense/NONSENSEEEEEEEEEEEEE/g" "$file"
}

for file in "${files[@]}"; do
  echo "Updating $file"
  # replace_in_files "$file"
  replace_in_tests "$file"

  # Only tests..
  # if [[ "$file" == *"test"* ]]; then
   
  # fi
done


